mapper.select:
select scd.sys_id, scd.link_sys_id, scm.common_cd as master_common_cd, scd.common_cd, scd.common_nm, scd.use_yn from sys_common_detail scd left join sys_common_master scm on scm.sys_id = scd.link_sys_id where 1=1 and link_sys_id = #{linkSysId}
and ( scd.common_cd like concat('%', #{searchCond}, '%') or scd.common_nm like concat('%', #{searchCond}, '%') )
and scd.delete_yn = 'N' order by scd.ord_no asc

select COUNT(*) > 0 from sys_common_detail where 1=1 and common_cd in
#{item.commonCd}
and link_sys_id = #{tempLinkSysId}

select scd.sys_id, scd.link_sys_id, scm.common_cd as master_common_cd, scd.common_cd, scd.common_nm, scd.use_yn from sys_common_detail scd left join sys_common_master scm on scm.sys_id = scd.link_sys_id where 1=1 and common_cd in
#{item.commonCd}
and scd.delete_yn = 'N' order by scd.ord_no asc
